var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"도와주셔서 감사합니다.","JPN":"助けてくれてありがとうございます。","ENG":"Thank you for your help.","TWN":"謝謝你的幫忙。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"다음에라도 은혜를 갚을 기회가 있다면 좋을 텐데요.","JPN":"恩返しできる機会があるといいんですが。","ENG":"I hope I can repay you later.","TWN":"希望下次有機會回報你。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"……마음에 두지 마시죠. 저 같은 것과는 되도록 깊이 얽히지 않으시는 편이 좋습니다.","JPN":"……お気になさらないでください。私ごときとは、なるべく関わらないほうがよろしいでしょう。","ENG":"Never mind. It’s in your best interest not to get involved with a lowly being such as myself.","TWN":"……不用放在心上。不要和我這種人有什麼牽扯比較好。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그, 그런가요?","JPN":"そ、そうなんですか？","ENG":"I-is that so?","TWN":"會…會嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그나저나…… 숲에 이런 집이 있었다니 신기하네요.","JPN":"ところで……森の中にこんな家があるなんて不思議ですね。","ENG":"Anyway... I didn’t expect to see a cabin in the middle of a forest.","TWN":"不過……樹林裡竟然有種的房子，真是奇妙。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"주위가 적막한 편이 마음을 가다듬기 좋으니 말이지요.","JPN":"周りが静かなほうが心を整えやすいものでございますから。","ENG":"This place is very quiet. It helps you compose yourself.","TWN":"周圍比較安靜，比較好控制情緒。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"일행 분의 응급치료는 마쳤습니다. 뼈가 어긋나진 않아서 다행이군요.","JPN":"お連れ様の応急手当は終わりました。\\n骨がずれていなかったのが幸いでした。","ENG":"I treated your friend’s leg. Fortunately, his bones were in the right place.","TWN":"已經先幫你的朋友處理完患部，幸好沒有骨折。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"끙, 덕분에 살았어. 혹시 의사야?","JPN":"ああ、おかげで助かった。もしかして医者か？","ENG":"Urgh. Thank you. Are you a doctor?","TWN":"嗯，謝謝你，你是醫生嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"그건 아니지만, 미약한 지식이나마 도움이 되길 바라면서 배웠을 뿐입니다.","JPN":"そうではございませんが、微々たる知識でも役に立てればと思い、学んだだけでございます。","ENG":"No, but I did learn such practices in hopes of helping others one day.","TWN":"我不是醫生，但有學過一些，想說或許有可以派上用場的時候。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"전시에는 사소한 이유와 무지 탓에 목숨을 잃는 경우도 부지기수니까요.","JPN":"戦時中は些細な理由や無知のせいで命を落とすことも多々ありますゆえ。","ENG":"During the war, trivial things and ignorance could kill you.","TWN":"畢竟在戰爭時，若是多些知識或能力，或許可以減少許多傷亡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"전시……?","JPN":"戦時……？","ENG":"War?","TWN":"戰爭……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"부상은 심하지 않았어요. 추락한 헬기가 폭발하지 않은 것도 다행이군요.","JPN":"お怪我はひどいものではございません。\\n墜落したヘリコプターが爆発しなかったのも幸いでした。","ENG":"Your injury was not serious. You were fortunate that the helicopter didn’t explode.","TWN":"傷勢不嚴重，幸好迫降時直升機沒有爆炸。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"……불시착 전에 연료통을 분리했을 뿐이야.","JPN":"……不時着前に燃料タンクを取り外しただけだ。","ENG":"I detached the fuel tank before we crash landed.","TWN":"……我只是在迫降前將油箱分離而已。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"나머지는 운에 맡겼던 거지.","JPN":"あとは運に任せただけさ。","ENG":"I left the rest to luck.","TWN":"其他的就靠運氣囉！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"그런 것도 배우지 않으면 모르는 사실이죠.","JPN":"そういったことも、学ばなければ知ることのないものでしょう。","ENG":"You could do that because you knew what you were doing.","TWN":"這些事也都是需要學習才會知道的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"잘 해주셨습니다.","JPN":"よくぞご対応くださいました。","ENG":"You did well.","TWN":"你做得很好。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"크흠, 그건 그렇고 당신…….","JPN":"こほん、それにしてもあんた……","ENG":"*Dry Cough* By the way...","TWN":"咳咳，先不說這些，你……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"여긴 여자 혼자 있기엔 위험한 장소야. 지금도 여전히 침식체가 들끓고 있어.","JPN":"ここは女一人でいるには危険な場所だ。\\n今も侵食体が湧いている。","ENG":"This is not the safest place for a woman. It’s filled with C.O.s.","TWN":"這裡現在很危險，侵蝕體正朝這邊湧來，一個女人家待在這裡很危險。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"치료를 도와준 건 고맙지만 당장 여길 떠나는 편이 좋아.","JPN":"治療してくれたのはありがたいが、今すぐここを離れたほうがいい。","ENG":"Thank you for helping us, but I suggest you leave this place at once.","TWN":"我很感謝你幫我治療，但你還是趕快離開這裡吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"그건 걱정 마시죠. 침식현상은 잠시 소강상태에 접어들었습니다.","JPN":"それは心配無用でございます。侵食現象はしばし小康状態に入りました。","ENG":"Don’t worry about me. The Counterside Effect is in a lull.","TWN":"請放心，侵蝕現象目前有緩和的跡象。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"안테나 역할을 하던 거대 침식체를 누군가 쓰러뜨린 덕분에, 남은 침식체들은 군체를 유지하지 못하고 흩어졌습니다.","JPN":"アンテナの役割をしていた巨大侵食体をどなたかが\\n倒してくださったおかげで、残った侵食体は群体を維持できず散乱しました。","ENG":"Thanks to whoever killed the giant C.O. which was acting as an antenna, the rest of the horde dissipated.","TWN":"多虧有人擊倒那隻帶頭的巨大侵蝕體，其他的侵蝕體現在應該已經一哄而散。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"꽤나 자세히 알고 있군. 침식체 전문가라도 돼?","JPN":"かなり詳しいようだな。侵食体の専門家か？","ENG":"You’re very knowledgeable. What are you, a C.O. expert?","TWN":"你知道的還真清楚，你是侵蝕體專家嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"……저는 한때 나나하라 가문 연합 밑에서 일하던 시녀입니다.","JPN":"……私はかつて七原家連合に仕えていた侍女でございます。","ENG":"... I used to be a servant of the Nanahara Family Alliance.","TWN":"……我曾是在七原家族聯盟底下工作的侍女。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"지금은 명예를 저버린 가문의 명맥을 이런 조용한 곳에서 구차하게 이어 나가고 있을 뿐이지만요.","JPN":"今は名誉を傷つけた家門の血筋を、\\nこのような静かなところで恥ずかしながら受け継いでいるだけでございますが。","ENG":"But now I’m just leading a humiliating life here, bearing the name of my disgraced family.","TWN":"家族的名譽掃地後，現在只能在這種地方，苟延殘喘地延續家族的命脈。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"뭐야. 어쩐지 쓰는 무기가 심상치 않더라니.","JPN":"なんだ、どうりで使ってる武器が普通じゃなかったわけか。","ENG":"I should have known when I saw your weapon.","TWN":"難怪～你用的武器跟一般人不太一樣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"당신도 연합을 떠난 가문 사람이었어?","JPN":"あんたも連合を去った家門の一人か？","ENG":"So you’re one of the families that left the Alliance?","TWN":"你也是離開聯盟的家族成員嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"아, 이쪽 눈치 볼 필요 없어.","JPN":"ああ、こっちの顔色を伺う必要はない。","ENG":"Don’t worry about us.","TWN":"喔，你不用擔心。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"우리도 당장 얼마 전까지 연합하고 연락 안 하고 살았으니까.","JPN":"オレたちもつい最近まで連合には連絡すらしてなかったからな。","ENG":"Our families also kept their distance from the Alliance.","TWN":"我們和聯盟一直都沒有交集的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"……카토리 마사키.","JPN":"……香取雅紀。","ENG":"... Katori Masaki.","TWN":"……香取雅紀。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"그게 당신의 이름이겠군요.","JPN":"それが貴方様のお名前ですね。","ENG":"That must be your name.","TWN":"這是你的名字吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"내 이름을 어떻게…","JPN":"オレの名前をどこで……","ENG":"How did you...","TWN":"你怎麼會知道我的…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"아, 아니!","JPN":"い、いや！","ENG":"I-I mean!","TWN":"不…不對！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 몸의 이름은 오오가미 마사키!","JPN":"オレ様の名前は大神雅紀！","ENG":"My name is Ogami Masaki!","TWN":"我的名字是大神雅紀！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"오오가미 흑막조의 조장인 이 몸이 그런 촌스러운 이름일 것 같냐!","JPN":"大神黒幕組の組長であるこのオレ様が、あんなだっせえ名前のはずがないだろ！","ENG":"I am the boss of Ogami's Shadow Group! There’s no way I’d have such a stupid name!","TWN":"我可是黑幕組的組長，名字怎麼可能那麼土！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"호방한 성정도 닮으셨군요. 당신의 아버지와 말이죠.","JPN":"豪放な性格もよく似ておられますね。貴方のお父上と。","ENG":"You are very vigorous. Just like your father.","TWN":"連奔放的個性也很像呢。我說你和你的父親。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키의…… 아버지?","JPN":"雅紀の……お父さん？","ENG":"Masaki’s father?","TWN":"雅紀的…… 爸爸？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"……쳇.","JPN":"……チッ。","ENG":"Sheesh...","TWN":"……嗟。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"돌아가자, 미나토.","JPN":"帰るぞ、湊。","ENG":"Let’s go, Minato.","TWN":"我們回去吧，南裕夏。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"우리가 여기 너무 오래 있으면 사람들이 죽은 줄 알 거다.","JPN":"ここに長居してたら、みんなにオレたちが死んだと思われるだろ。","ENG":"People might think we’re dead if we stay here too long.","TWN":"我們在這裡待太久的話，大家會以爲我們已經死了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아, 그래.","JPN":"あ、確かにそうだね。","ENG":"Oh, yeah.","TWN":"喔，好。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"그러면 연합 본부까지 동행해 드리겠습니다.","JPN":"それでは、連合本部まで同行させていただきます。","ENG":"Then let me take you to Alliance headquarters.","TWN":"那我送你們回聯盟。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"네? 괜찮으시겠어요?","JPN":"え？　いいんですか？","ENG":"Are you sure?","TWN":"嗯？你可以嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"숲에는 아직 침식체들이 많습니다.","JPN":"森にはまだ侵食体が多数残っています。","ENG":"The forest is still filled with C.O.s.","TWN":"樹林裡還有很多侵蝕體。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_QM","text":{"KOREA":"그리고 두 분 중 지금 제대로 싸울 수 있는 분은 없는 것 같군요.","JPN":"そして、今のお二人はまともに戦える状態ではないようですから。","ENG":"I don’t think you’ll be able to defend yourselves in your current status.","TWN":"更何況，以二位現在的情況，應該都無法成為戰力。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"봉인들은 모두 무사히 지켜냈다고 합니다.","JPN":"封印はすべて無事に守り抜いたそうです。","ENG":"The seals are safe for now.","TWN":"聽說封印都順利守住了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"도시로 새어나간 피해도 경미한 수준입니다.","JPN":"都市に広がった被害も軽微なものです。","ENG":"The city is not badly damaged either.","TWN":"城市的損失也不算太嚴重。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"이걸로 큰 고비는 넘긴 셈이군요.","JPN":"これでひとまず峠は越えたようですね。","ENG":"We’ve turned the corner.","TWN":"算是暫時渡過難關。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"연합원들의 상태는 어떤가요?","JPN":"連合員の状態はいかかですか？","ENG":"How are the Alliance members?","TWN":"聯盟成員現在狀況如何？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"제1 봉인역 대장을 맡고 있던 토다 당주가 전사…….","JPN":"第一封印域隊長を務めていた戸田家当主が戦死……","ENG":"The 1st Seal Domain captain and the family leader Toda is lost...","TWN":"擔任第1封印域隊長的戶田堂主戰死……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그 외에도 사상자가 몇 있으나 전세가 흔들릴 정도는 아닙니다.","JPN":"その他、死傷者が数名いますが、戦況が変わるほどではありません。","ENG":"We have some other causalities as well, but it won’t affect our situation negatively.","TWN":"除此之外，還有一些傷亡，但不至於影響局勢。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"카미이즈미의 상태는 지금 어떤가요?","JPN":"現在の上泉の状態はいかがですか？","ENG":"How is Kamiizumi?","TWN":"那上泉的狀況如何？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"정화 작업은 마무리 단계지만, 당장 기동하는 것은 어렵습니다.","JPN":"浄化作業は仕上げの段階ですが、今すぐ起動するのは難しいでしょう。","ENG":"The purification is almost over, but we can’t activate it right now.","TWN":"淨化作業雖然已進入收尾階段，但無法立刻行動。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"주인을 알아보는 까다로운 신물이니까요.","JPN":"主を見極める気難しい神物ですゆえ。","ENG":"The artifact is very particular when choosing its master.","TWN":"畢竟是會認主人的信物。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"원하신다면 제가 직접 마사키님을 설득해보지요.","JPN":"お望みでしたら、私が直接雅紀様を説得してみます。","ENG":"If you want, I’ll try to persuade Sir Masaki myself.","TWN":"若是堂主同意，我可以親自說服雅紀。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"아뇨, 괜찮습니다.","JPN":"いいえ、大丈夫です。","ENG":"No, it’s quite alright.","TWN":"不用，沒關係。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"같은 연합이라는 이유로 그분의 선택을 강요하고 싶진 않으니까요.","JPN":"同じ連合という理由で、あの方の選択を強要したくはありません。","ENG":"I don’t want to force him a decision just because his family belongs to the Alliance.","TWN":"我不想用聯盟成員的身分對他施壓。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그런 식으로 결정을 떠넘기기만 하시는 건 곤란합니다.","JPN":"そのように決定を押し付ける一方では困ります。","ENG":"You will have to make the decision eventually.","TWN":"這種鴕鳥心態是不行的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치와의 결전은, 연합이 언젠가 마주해야만 할 숙명. 피하기만 하는 것은 답이 되지 않지요.","JPN":"オロチとの決戦は、連合がいつか向き合うべき宿命。避けてばかりでは解決できませぬ。","ENG":"The battle between Orochi and the Alliance is a destined path. We can’t avoid it forever.","TWN":"與大蛇的決戰，是聯盟總有一天必須面對的宿命。逃避不能解決事情。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"알고 있어요.","JPN":"承知しています。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 저는 더 이상 제가 아닌 누군가를 희생시키고 싶지 않습니다.","JPN":"しかし、私はもう私以外の誰かを犠牲にしたくはありません。","ENG":"But I don’t want to sacrifice others in my stead again.","TWN":"我只是不想再犧牲任何人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하물며 그 싸움이 실패하면, 이번엔 그때보다 훨씬 많은 사람들이 죽게 되겠죠.","JPN":"ましてや、その戦いが失敗すれば、今度はあの時よりもはるかに多くの方々が命を落とすでしょう。","ENG":"If we fail, more people will lose their lives this time.","TWN":"更何況，萬一失敗，這次會死更多人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그럴 바엔 차라리…… 바람이 속삭여 준 결말이 나을지도 모릅니다.","JPN":"ならばいっそ……風がささやいてくれた結末のほうが良いのかもしれません。","ENG":"If that’s the case... I would rather prefer the end that the wind whispered to me.","TWN":"與其如此…那風聲告訴我的結局或許好一點。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그 결말이란 것이 부디, 당주님을 해치지는 않았으면 좋겠군요. 아직 연합원들에겐 당주님이 필요하니까요.","JPN":"その結末がどうかご当主様自身を傷つけるものではないことを願います。\\n連合員にはまだご当主が必要ですから。","ENG":"I hope the end you heard doesn’t harm you. The Alliance still needs you.","TWN":"希望那個結局，不會危害到堂主。畢竟聯盟成員都還需要堂主。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"이 늙은이에게도 마찬가지고 말이지요.","JPN":"もちろんこの老いぼれも含めてです。","ENG":"The same goes for this old.","TWN":"我這個老人家也是。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"얼굴빛이 좋지 않습니다, 당주님. 장로님께서 무슨 말씀이라도 하신 건가요.","JPN":"顔色がよくありませんね、当主。長老に何か言われたのですか。","ENG":"You don’t look well, Lady Nanahara. Is it because of something that the elder told you?","TWN":"堂主的臉色似乎不太好，長老有說什麼嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"괜찮아. 그런 것 때문은 아니니까.","JPN":"大丈夫よ。そういうことではないから。","ENG":"No, it’s not that.","TWN":"我沒事，不是因爲長老的關係。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그저……","JPN":"ただ……","ENG":"It's just that...","TWN":"只是……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오늘따라 이 검이 참 무겁게 느껴지는구나.","JPN":"今日はいつもよりこの剣が本当に重く感じるの。","ENG":"The sword in my hand feels unusually heavy today.","TWN":"今天覺得這把劍特別沉重。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"선대께서 내게 바라신 모습은 이런 게 아니었을 텐데 말이다.","JPN":"先代が私に願った姿はこのようなものではなかったはず……","ENG":"I feel like I’m not fulfilling the expectations of the previous leader.","TWN":"先祖對我的期待應該不是這樣的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"토다 당주의 소식은 저도 안타깝습니다.","JPN":"戸田家当主の話はとても残念です。","ENG":"I am also saddened by the news of Toda.","TWN":"戶田堂主的事我也很遺憾。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"연합의 뜻을 위해서라면 다시 얻은 목숨이라도 기꺼이 바칠 훌륭한 무사였죠.","JPN":"連合のためなら再び得た命でも喜んで捧げる立派な武士でした。","ENG":"He was a great warrior who was willing to sacrifice himself for the Alliance again and again.","TWN":"他是一位出色的武士，只要是聯盟的意思，他都會毫不猶豫地將自己的性命獻上。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그러니 그분을 연민하지 마십시오.","JPN":"ですので、あの方を哀れに思わないでください。","ENG":"So please don’t feel sorry for him.","TWN":"所以請不要憐憫他。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"지금 연합원들에게 필요한 건 흔들림 없이 자신들을 이끌어 줄 사람입니다.","JPN":"今連合員に必要なのは、動揺せず自分たちを導いてくれる存在です。","ENG":"What the Alliance needs now is an unwavering leader who can lead them to victory.","TWN":"現在聯盟成員需要的是，可以堅定地帶領他們的人。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유는 정말 강하구나.","JPN":"千冬は本当に強いね。","ENG":"Chifuyu, you are a strong person.","TWN":"千冬真的很堅強呢。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"어릴 적에도 넌 내게 가장 의지가 되어 주던 듬직한 동생이었지.","JPN":"貴方は幼い頃から私にとって一番頼りになる頼もしい妹だったわ。","ENG":"I always relied on you, even when we were very young.","TWN":"小時候我最倚靠的也是你。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"몰래 집을 나섰다가 큰 개를 마주쳤을 때도.","JPN":"こっそり家から抜け出して大きな犬に出くわした時も。","ENG":"When I saw a big dog while sneaking out from the house...","TWN":"偷跑出家門，遇到惡犬的時候。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당주가 되기 싫다고 산에 숨었다가 멧돼지에게 쫓겼을 때도.","JPN":"当主になりたくないと山に隠れて、イノシシに追いかけられた時も。","ENG":"When a boar came after me while I was hiding in the mountains to avoid becoming the leader of the family...","TWN":"因為不想成爲堂主，躲在山上遇到山豬的時候。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"난생 처음 커다란 침식체를 만났을 때도.","JPN":"生まれて初めて大きな侵食体を前にした時も。","ENG":"And when I met a huge C.O. for the first time in my life...","TWN":"還有生平第一次遇到巨大侵蝕體的時候。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다칠 게 뻔한데, 너는 언제나 날 앞에서 지켜주었지.","JPN":"ケガするに決まっているのに、貴方はいつも私の前で守ってくれた。","ENG":"You were always there for me, protecting me despite the danger.","TWN":"你明知道會受傷，卻總是擋在前面保護我。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그럴 때마다 나에게 따끔히 한마디 할 수 있었을 텐데, 넌 그러지 않았다.","JPN":"そのたびに私を叱ることもできたはずなのに、貴方はそうしなかった。","ENG":"You could have complained, but you never did.","TWN":"明明可以狠狠地罵我一句，你卻沒有。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그때도 지금도…… 난 너에게 몹쓸 짐만 지우고 있는 것 같아 미안하구나.","JPN":"あの時も今も……私は貴方に負担をかけてばかりで、ごめんなさい。","ENG":"I feel like... I’m just a burden to you.","TWN":"無論是那時還是現在……我好像都只是拖累你的包袱，真是對不起。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"전 당주님이 달라지길 원했던 적이 없습니다.","JPN":"私は当主に変わってほしいと望んだことはありません。","ENG":"I never wanted you to change.","TWN":"我從來沒想過要堂主改變。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"지금은…… 그때와 달라지신 것 같지만요.","JPN":"今は……あの時とは変わったようですが。","ENG":"But now... you seem to have changed.","TWN":"雖然……現在似乎已經和當時不太一樣。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……치후유.","JPN":"……千冬。","ENG":"Chifuyu.","TWN":"……千冬。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나는…….","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MEMBER_EXTRA_NANA_A","text":{"KOREA":"당주님. 급히 나와보셔야 할 것 같습니다.","JPN":"ご当主、大至急お越しになっていただけますでしょうか。","ENG":"Lady Nanahara, there is something you have to see.","TWN":"堂主，請您趕緊出來看看。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네? 무슨 일이죠?","JPN":"はい？　どうしましたか？","ENG":"Yes? What is it?","TWN":"嗯？發生什麼事？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEMBER_EXTRA_NANA_A","text":{"KOREA":"하야미 가문의 여식이…… 돌아왔습니다.","JPN":"速水家の娘が……帰ってきました。","ENG":"The daughter of the Hayami family is... here.","TWN":"速水家族的女兒……回來了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};